sql:
SELECT COUNT(finding_id) 
FROM audit_findings 
WHERE severity = 'High';

SELECT COUNT(*) 
FROM compliance_status 
WHERE status = 'Non-compliant';

SELECT T2.name
   FROM action_plans T1
   INNER JOIN personnel T2 ON T1.responsible_personnel_id = T2.personnel_id
   WHERE T1.progress_percentage = (
     SELECT MAX(progress_percentage) FROM action_plans
   );

SELECT action_plan_description 
FROM action_plans 
WHERE action_plan_id = 1;

